-- ============ Ford ============
DO $do$
DECLARE
  v_brand_id TEXT;
  v_model_id TEXT;
BEGIN
  INSERT INTO brands (id, name) SELECT gen_random_uuid(), 'Ford'
    WHERE NOT EXISTS (SELECT 1 FROM brands WHERE LOWER(name) = LOWER('Ford'));
  SELECT id::text INTO v_brand_id FROM brands WHERE LOWER(name) = LOWER('Ford');
  INSERT INTO models (name, brand_id) SELECT 'Bronco', v_brand_id
    WHERE NOT EXISTS (SELECT 1 FROM models WHERE brand_id = v_brand_id AND LOWER(name) = LOWER('Bronco'));
  SELECT id::text INTO v_model_id FROM models WHERE brand_id = v_brand_id AND LOWER(name) = LOWER('Bronco');
  INSERT INTO versions (name, model_id) SELECT 'Badlands 2.7 V6 4x4', v_model_id::int
    WHERE v_model_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM versions WHERE model_id = v_model_id::int AND LOWER(name) = LOWER('Badlands 2.7 V6 4x4'));
  INSERT INTO versions (name, model_id) SELECT 'Big Bend 2.3 EcoBoost 4x4', v_model_id::int
    WHERE v_model_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM versions WHERE model_id = v_model_id::int AND LOWER(name) = LOWER('Big Bend 2.3 EcoBoost 4x4'));
