DO $do$
DECLARE
  v_brand_id TEXT;
  v_model_id TEXT;
BEGIN
  INSERT INTO brands (id, name) SELECT gen_random_uuid(), 'Jetour'
    WHERE NOT EXISTS (SELECT 1 FROM brands WHERE LOWER(name) = LOWER('Jetour'));
  SELECT id::text INTO v_brand_id FROM brands WHERE LOWER(name) = LOWER('Jetour');
  INSERT INTO models (name, brand_id) SELECT 'Dashing', v_brand_id
    WHERE NOT EXISTS (SELECT 1 FROM models WHERE brand_id = v_brand_id AND LOWER(name) = LOWER('Dashing'));
  SELECT id::text INTO v_model_id FROM models WHERE brand_id = v_brand_id AND LOWER(name) = LOWER('Dashing');
