-- ============ Leapmotor ============
DO $do$
DECLARE
  v_brand_id TEXT;
  v_model_id TEXT;
BEGIN
  INSERT INTO brands (id, name) SELECT gen_random_uuid(), 'Leapmotor'
    WHERE NOT EXISTS (SELECT 1 FROM brands WHERE LOWER(name) = LOWER('Leapmotor'));
  SELECT id::text INTO v_brand_id FROM brands WHERE LOWER(name) = LOWER('Leapmotor');
  INSERT INTO models (name, brand_id) SELECT 'B10', v_brand_id
    WHERE NOT EXISTS (SELECT 1 FROM models WHERE brand_id = v_brand_id AND LOWER(name) = LOWER('B10'));
  SELECT id::text INTO v_model_id FROM models WHERE brand_id = v_brand_id AND LOWER(name) = LOWER('B10');
  INSERT INTO versions (name, model_id) SELECT 'Comfort EV', v_model_id::int
