-- ============ Volkswagen ============
DO $do$
DECLARE
  v_brand_id TEXT;
  v_model_id TEXT;
BEGIN
  INSERT INTO brands (id, name) SELECT gen_random_uuid(), 'Volkswagen'
    WHERE NOT EXISTS (SELECT 1 FROM brands WHERE LOWER(name) = LOWER('Volkswagen'));
  SELECT id::text INTO v_brand_id FROM brands WHERE LOWER(name) = LOWER('Volkswagen');
